    public void handleOrderBook(Client client, Object message)
    {
        //
        //     {
        //         "channel": "market_ethbtc_simple_depth_step0",
        //         "ts": 1670056708670,
        //         "tick": {
        //             "buys": [
        //                 [
        //                     "0.075170",
        //                     "67.153"
        //                 ],
        //                 [
        //                     "0.075169",
        //                     "17.195"
        //                 ],
        //                 [
        //                     "0.075166",
        //                     "29.788"
        //                 ],
        //             ]
        //              "asks": [
        //                 [
        //                     "0.075171",
        //                     "0.256"
        //                 ],
        //                 [
        //                     "0.075172",
        //                     "0.160"
        //                 ],
        //             ]
        //         }
        //     }
        //
        Object channel = this.safeString(message, "channel");
        Object parts = Helpers.split(channel, "_");
        Object channelKind = this.safeString(parts, 1);
        Object isFutures = (Helpers.isEqual(channelKind, "e"));
        Object market = null;
        if (Helpers.isTrue(isFutures))
        {
            Object wsBaseQuote = this.safeStringLower(parts, 2);
            market = this.findSwapMarketByWsBaseQuote(wsBaseQuote);
        } else
        {
            Object marketId = this.safeStringUpper(parts, 1);
            market = this.safeMarket(marketId);
        }
        Object symbol = Helpers.GetValue(market, "symbol");
        Object timestamp = this.safeInteger(message, "ts");
        Object tick = this.safeValue(message, "tick", new java.util.HashMap<String, Object>() {{}});
        Object parseable = tick;
        if (Helpers.isTrue(isFutures))
        {
            Object rawAsks = this.safeList(tick, "asks", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object rawBuys = this.safeList(tick, "buys", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            final Object finalSymbol = symbol;
            parseable = new java.util.HashMap<String, Object>() {{
                put( "asks", BitrueCore.this.parseContractBidsAsks(rawAsks, finalSymbol) );
                put( "buys", BitrueCore.this.parseContractBidsAsks(rawBuys, finalSymbol) );
            }};
        }
        if (!Helpers.isTrue((Helpers.inOp(this.orderbooks, symbol))))
        {
            Helpers.addElementToObject(this.orderbooks, symbol, this.orderBook());
        }
        Object orderbook = Helpers.GetValue(this.orderbooks, symbol);
        Object snapshot = this.parseOrderBook(parseable, symbol, timestamp, "buys", "asks");
        Helpers.callDynamically(orderbook, "reset", new Object[]{snapshot});
        Object messageHash = Helpers.add("orderbook:", symbol);
        client.resolve(orderbook, messageHash);
    }

    public Object findSwapMarketByWsBaseQuote(Object wsBaseQuote)
    {
        Object symbols = Helpers.objectKeys(this.markets);
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(symbols)); i++)
        {
            Object candidate = Helpers.GetValue(this.markets, Helpers.GetValue(symbols, i));
            if (!Helpers.isTrue(Helpers.GetValue(candidate, "swap")))
            {
                continue;
            }
            Object baseId = this.safeStringLower(candidate, "baseId", "");
            Object quoteId = this.safeStringLower(candidate, "quoteId", "");
            if (Helpers.isTrue(Helpers.isEqual(Helpers.add(baseId, quoteId), wsBaseQuote)))
            {
                return candidate;
            }
        }
        return null;
    }

    public Object parseContractBidsAsks(Object bidsAsks, Object symbol)
    {
        Object result = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(bidsAsks)); i++)
        {
            Object level = Helpers.GetValue(bidsAsks, i);
            Object price = this.safeNumber(level, 0);
            Object rawAmount = this.safeNumber(level, 1);
            Object amount = this.convertFromRawQuantity(symbol, rawAmount);
            ((java.util.List<Object>)result).add(new java.util.ArrayList<Object>(java.util.Arrays.asList(price, amount)));
        }
        return result;
    }

    public Object convertFromRawQuantity(Object symbol, Object rawQuantity)
    {
        if (Helpers.isTrue(Helpers.isEqual(rawQuantity, null)))
        {
            return null;
        }
        Object market = this.market(symbol);
        if (!Helpers.isTrue(Helpers.GetValue(market, "contract")))
        {
            return rawQuantity;
        }
        Object contractSize = this.safeNumber(market, "contractSize", 1);
        return Helpers.multiply(rawQuantity, contractSize);
    }

