    public void handleTrades(Client client, Object message)
    {
        //
        //     {
        //         "event_rep": "",
        //         "channel": "market_e_btcusdt_trade_ticker",
        //         "ts": 1721743391000,
        //         "status": "ok",
        //         "tick": {
        //             "data": [
        //                 {
        //                     "amount": "1666656191.2",
        //                     "ds": "2024-07-23 22:03:11",
        //                     "price": "66008.8",
        //                     "side": "SELL",
        //                     "ts": 1721743391398,
        //                     "vol": "25249"
        //                 }
        //             ]
        //         }
        //     }
        //
        Object channel = this.safeString(message, "channel");
        Object parts = Helpers.split(channel, "_");
        Object wsBaseQuote = this.safeStringLower(parts, 2);
        Object market = this.findSwapMarketByWsBaseQuote(wsBaseQuote);
        if (Helpers.isTrue(Helpers.isEqual(market, null)))
        {
            return;
        }
        Object symbol = Helpers.GetValue(market, "symbol");
        Object tick = this.safeValue(message, "tick", new java.util.HashMap<String, Object>() {{}});
        Object data = this.safeList(tick, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object appended = false;
        Object stored = this.safeValue(this.trades, symbol);
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(data)); i++)
        {
            if (Helpers.isTrue(Helpers.isEqual(stored, null)))
            {
                Object limit = this.safeInteger(this.options, "tradesLimit", 1000);
                stored = new ArrayCache(((Number)limit).intValue());
                Helpers.addElementToObject(this.trades, symbol, stored);
            }
            Object trade = this.parseWsTrade(Helpers.GetValue(data, i), market);
            Helpers.callDynamically(stored, "append", new Object[]{trade});
            appended = true;
        }
        if (Helpers.isTrue(appended))
        {
            Object messageHash = Helpers.add("trades:", symbol);
            client.resolve(stored, messageHash);
        }
    }

