    public void handleTicker(Client client, Object message)
    {
        //
        //     {
        //         "channel": "market_e_btcusdt_ticker",
        //         "ts": 1506584998239,
        //         "tick": {
        //             "amount": 123.1221,
        //             "vol": 1212.12211,
        //             "open": 2233.22,
        //             "close": 1221.11,
        //             "high": 22322.22,
        //             "low": 2321.22,
        //             "rose": -0.2922
        //         },
        //         "status": "ok"
        //     }
        //
        Object channel = this.safeString(message, "channel");
        Object parts = Helpers.split(channel, "_");
        Object wsBaseQuote = this.safeStringLower(parts, 2);
        Object market = this.findSwapMarketByWsBaseQuote(wsBaseQuote);
        if (Helpers.isTrue(Helpers.isEqual(market, null)))
        {
            return;
        }
        Object symbol = Helpers.GetValue(market, "symbol");
        Object tick = this.safeValue(message, "tick");
        if (Helpers.isTrue(Helpers.isEqual(tick, null)))
        {
            return;
        }
        Object timestamp = this.safeInteger(message, "ts");
        Object parsed = this.parseWsTicker(tick, market, timestamp);
        Helpers.addElementToObject(this.tickers, symbol, parsed);
        Object messageHash = Helpers.add("ticker:", symbol);
        client.resolve(parsed, messageHash);
    }

    public Object parseWsTicker(Object tick, Object market, Object... optionalArgs)
    {
        Object timestamp = Helpers.getArg(optionalArgs, 0, null);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object rawVol = this.safeNumber(tick, "vol");
        Object rawAmount = this.safeNumber(tick, "amount");
        Object baseVolume = this.convertFromRawQuantity(symbol, rawVol);
        Object quoteVolume = this.convertFromRawQuantity(symbol, rawAmount);
        Object close = this.safeNumber(tick, "close");
        Object rose = this.safeNumber(tick, "rose");
        Object percentage = ((Helpers.isTrue((Helpers.isEqual(rose, null))))) ? null : Helpers.multiply(rose, 100);
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "info", tick );
            put( "symbol", symbol );
            put( "timestamp", timestamp );
            put( "datetime", BitrueCore.this.iso8601(timestamp) );
            put( "high", BitrueCore.this.safeNumber(tick, "high") );
            put( "low", BitrueCore.this.safeNumber(tick, "low") );
            put( "bid", null );
            put( "bidVolume", null );
            put( "ask", null );
            put( "askVolume", null );
            put( "vwap", null );
            put( "open", BitrueCore.this.safeNumber(tick, "open") );
            put( "close", close );
            put( "last", close );
            put( "previousClose", null );
            put( "change", null );
            put( "percentage", percentage );
            put( "average", null );
            put( "baseVolume", baseVolume );
            put( "quoteVolume", quoteVolume );
        }}, market);
    }

